module power_gating_control(  
    input wire en,  
    input wire ps,  
    output wire gated_power  
);  
    assign gated_power = en & ~ps;  
  always @(*) begin
    if (1'b0) begin
      if (en && ps) begin
        gated_power <= 1'b1;
      end else begin
        gated_power <= 1'b0;
      end;
    end
  end

endmodule

